def solve(creatinine_clearance, hematocrit, heart_rate, systolic_bp, is_male, has_heart_failure, has_diabetes, has_vascular_disease_stroke):
    # Step 1: creatinine_clearance_score
    # Determine the score based on creatinine clearance (mL/min)
    if creatinine_clearance <= 15:
        creatinine_clearance_score = 39
    elif 16 <= creatinine_clearance <= 30:
        creatinine_clearance_score = 35
    elif 31 <= creatinine_clearance <= 60:
        creatinine_clearance_score = 28
    elif 61 <= creatinine_clearance <= 90:
        creatinine_clearance_score = 17
    elif 91 <= creatinine_clearance <= 120:
        creatinine_clearance_score = 7
    else:  # >120
        creatinine_clearance_score = 0
    yield {
        "step_name": "creatinine_clearance_score",
        "step_description": "Determine the score based on creatinine clearance (mL/min)",
        "step_result": creatinine_clearance_score,
        "unit": None
    }

    # Step 2: hematocrit_score
    # Determine the score based on baseline hematocrit (%)
    if hematocrit < 31.0:
        hematocrit_score = 9
    elif 31.0 <= hematocrit <= 33.9:
        hematocrit_score = 7
    elif 34.0 <= hematocrit <= 36.9:
        hematocrit_score = 3
    elif 37.0 <= hematocrit <= 39.9:
        hematocrit_score = 2
    else:  # >= 40.0
        hematocrit_score = 0
    yield {
        "step_name": "hematocrit_score",
        "step_description": "Determine the score based on baseline hematocrit (%)",
        "step_result": hematocrit_score,
        "unit": None
    }

    # Step 3: heart_rate_score
    # Determine the score based on heart rate (beats/min)
    if heart_rate <= 70:
        heart_rate_score = 0
    elif 71 <= heart_rate <= 80:
        heart_rate_score = 1
    elif 81 <= heart_rate <= 90:
        heart_rate_score = 3
    elif 91 <= heart_rate <= 100:
        heart_rate_score = 6
    elif 101 <= heart_rate <= 110:
        heart_rate_score = 8
    elif 111 <= heart_rate <= 120:
        heart_rate_score = 10
    else:  # >= 121
        heart_rate_score = 11
    yield {
        "step_name": "heart_rate_score",
        "step_description": "Determine the score based on heart rate (beats/min)",
        "step_result": heart_rate_score,
        "unit": None
    }

    # Step 4: systolic_bp_score
    # Determine the score based on systolic blood pressure (mmHg)
    if systolic_bp <= 90:
        systolic_bp_score = 10
    elif 91 <= systolic_bp <= 100:
        systolic_bp_score = 8
    elif 101 <= systolic_bp <= 120:
        systolic_bp_score = 5
    elif 121 <= systolic_bp <= 180:
        systolic_bp_score = 1
    elif 181 <= systolic_bp <= 200:
        systolic_bp_score = 3
    else:  # >= 201
        systolic_bp_score = 5
    yield {
        "step_name": "systolic_bp_score",
        "step_description": "Determine the score based on systolic blood pressure (mmHg)",
        "step_result": systolic_bp_score,
        "unit": None
    }

    # Step 5: categorical_factors_score
    # Determine the combined score for sex, heart failure signs, diabetes, and vascular disease/stroke history
    sex_score = 0 if is_male else 8
    heart_failure_score = 7 if has_heart_failure else 0
    diabetes_score = 6 if has_diabetes else 0
    vascular_score = 6 if has_vascular_disease_stroke else 0
    categorical_score = sex_score + heart_failure_score + diabetes_score + vascular_score
    yield {
        "step_name": "categorical_factors_score",
        "step_description": "Determine the combined score for sex, heart failure signs, diabetes, and vascular disease/stroke history",
        "step_result": categorical_score,
        "unit": None
    }

    # Step 6: total_risk_score
    # Sum all individual scores to compute the total major bleeding risk score
    total_score = creatinine_clearance_score + hematocrit_score + heart_rate_score + systolic_bp_score + categorical_score
    yield {
        "step_name": "total_risk_score",
        "step_description": "Sum all individual scores to compute the total major bleeding risk score",
        "step_result": total_score,
        "unit": None
    }

    return total_score
